import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, User, Menu, X, MapPin } from 'lucide-react';
import MegaMenu from './megamenu';
import { useCart } from '../../hooks/usecart';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState(null);
  const { user, isAuthenticated } = useSelector((state) => state.auth);
  const { getItemCount } = useCart();
  const navigate = useNavigate();

  const categories = [
    {
      name: 'Living Room',
      slug: 'living-room',
      subcategories: [
        'Sofas',
        'TV Units',
        'Coffee Tables',
        'Bookshelves',
        'Shoe Racks',
      ],
    },
    {
      name: 'Bedroom',
      slug: 'bedroom',
      subcategories: [
        'Beds',
        'Wardrobes',
        'Dressers',
        'Nightstands',
        'Mattresses',
      ],
    },
    {
      name: 'Dining',
      slug: 'dining',
      subcategories: [
        'Dining Sets',
        'Dining Tables',
        'Chairs',
        'Cabinets',
        'Bar Furniture',
      ],
    },
    {
      name: 'Study',
      slug: 'study',
      subcategories: [
        'Study Tables',
        'Office Chairs',
        'Bookshelves',
        'Laptop Tables',
      ],
    },
    {
      name: 'Decor',
      slug: 'decor',
      subcategories: ['Wall Art', 'Mirrors', 'Clocks', 'Vases', 'Lamps'],
    },
  ];

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setIsSearchOpen(false);
    }
  };

  return (
    <>
      <header className="sticky top-0 z-50 bg-white shadow-sm">
        {/* Top Bar */}
        <div className="bg-primary-800 text-white text-xs py-2 px-4 text-center hidden md:block">
          <span>Free Shipping on Orders Above ₹10,000 | EMI Available</span>
        </div>

        {/* Main Navbar */}
        <div className="container mx-auto px-4">
          <div className="flex items-center justify-between h-14 md:h-16">
            {/* Mobile Menu Button */}
            <button
              className="md:hidden p-2 -ml-2"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              {isMenuOpen ? (
                <X className="w-6 h-6" />
              ) : (
                <Menu className="w-6 h-6" />
              )}
            </button>

            {/* Logo */}
            <Link to="/" className="flex-shrink-0">
              <h1 className="text-xl md:text-2xl font-bold text-primary-700 tracking-tight">
                Wooden<span className="text-primary-500">Street</span>
              </h1>
            </Link>

            {/* Desktop Navigation */}
            <nav className="hidden md:flex items-center space-x-6 ml-8">
              {categories.map((cat) => (
                <div
                  key={cat.slug}
                  className="relative group"
                  onMouseEnter={() => setActiveCategory(cat)}
                  onMouseLeave={() => setActiveCategory(null)}
                >
                  <Link
                    to={`/category/${cat.slug}`}
                    className="text-sm font-medium text-gray-700 hover:text-primary-600 py-5"
                  >
                    {cat.name}
                  </Link>
                </div>
              ))}
            </nav>

            {/* Right Actions */}
            <div className="flex items-center space-x-2 md:space-x-4">
              <button
                className="p-2 md:hidden"
                onClick={() => setIsSearchOpen(!isSearchOpen)}
              >
                <Search className="w-5 h-5 text-gray-700" />
              </button>

              <div className="hidden md:flex items-center text-sm text-gray-600 mr-2">
                <MapPin className="w-4 h-4 mr-1" />
                <span className="max-w-[100px] truncate">Deliver to...</span>
              </div>

              <div className="hidden md:block relative">
                <form onSubmit={handleSearch}>
                  <input
                    type="text"
                    placeholder="Search furniture..."
                    className="w-64 pl-10 pr-4 py-2 bg-gray-100 rounded-full text-sm focus:bg-white border border-transparent focus:border-primary-300 transition"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                  <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                </form>
              </div>

              <Link
                to={isAuthenticated ? '/account' : '/login'}
                className="p-2 hidden md:block"
              >
                <User className="w-5 h-5 text-gray-700" />
              </Link>

              <Link to="/cart" className="p-2 relative">
                <ShoppingCart className="w-5 h-5 text-gray-700" />
                {getItemCount() > 0 && (
                  <span className="absolute -top-0.5 -right-0.5 bg-brand-red text-white text-[10px] font-bold w-4 h-4 rounded-full flex items-center justify-center">
                    {getItemCount()}
                  </span>
                )}
              </Link>
            </div>
          </div>
        </div>

        {/* Mobile Search Bar */}
        {isSearchOpen && (
          <div className="md:hidden px-4 pb-3 border-t border-gray-100 pt-2">
            <form onSubmit={handleSearch} className="relative">
              <input
                type="text"
                placeholder="Search furniture..."
                className="w-full pl-10 pr-4 py-2.5 bg-gray-100 rounded-lg text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                autoFocus
              />
              <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
            </form>
          </div>
        )}

        {/* Mega Menu */}
        {activeCategory && (
          <MegaMenu
            category={activeCategory}
            onClose={() => setActiveCategory(null)}
          />
        )}
      </header>

      {/* Mobile Menu Overlay */}
      {isMenuOpen && (
        <div className="fixed inset-0 z-40 bg-white md:hidden">
          <div className="pt-16 px-4 pb-20 h-full overflow-y-auto">
            <div className="space-y-1">
              {categories.map((cat) => (
                <div key={cat.slug} className="border-b border-gray-100">
                  <Link
                    to={`/category/${cat.slug}`}
                    className="block py-3 text-base font-medium text-gray-900"
                    onClick={() => setIsMenuOpen(false)}
                  >
                    {cat.name}
                  </Link>
                  <div className="pl-4 pb-2 space-y-2">
                    {cat.subcategories.map((sub) => (
                      <Link
                        key={sub}
                        to={`/category/${cat.slug}/${sub
                          .toLowerCase()
                          .replace(' ', '-')}`}
                        className="block py-1.5 text-sm text-gray-600"
                        onClick={() => setIsMenuOpen(false)}
                      >
                        {sub}
                      </Link>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-6 pt-6 border-t border-gray-200">
              {!isAuthenticated ? (
                <Link
                  to="/login"
                  className="flex items-center py-3 text-base font-medium text-gray-900"
                  onClick={() => setIsMenuOpen(false)}
                >
                  <User className="w-5 h-5 mr-3" />
                  Login / Register
                </Link>
              ) : (
                <div className="space-y-3">
                  <p className="font-medium text-gray-900">
                    Hello, {user?.first_name || 'User'}
                  </p>
                  <Link
                    to="/account/orders"
                    className="block text-sm text-gray-600"
                  >
                    My Orders
                  </Link>
                  <Link
                    to="/account/addresses"
                    className="block text-sm text-gray-600"
                  >
                    Addresses
                  </Link>
                  <button className="text-sm text-red-600">Logout</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Navbar;
